// Fetch today's (or yesterday's) daily papers from HF API
const today = new Date();
const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');
const dateStr = `${yyyy}-${mm}-${dd}`;

const resp = await fetch(`https://huggingface.co/api/daily_papers?date=${dateStr}`);
if (!resp.ok) throw new Error(`HF API error: ${resp.status}`);
const papers = await resp.json();

// If no papers today, try yesterday
if (papers.length === 0) {
  const yesterday = new Date(today);
  yesterday.setDate(yesterday.getDate() - 1);
  const yd = `${yesterday.getFullYear()}-${String(yesterday.getMonth()+1).padStart(2,'0')}-${String(yesterday.getDate()).padStart(2,'0')}`;
  const resp2 = await fetch(`https://huggingface.co/api/daily_papers?date=${yd}`);
  if (resp2.ok) {
    const papers2 = await resp2.json();
    if (papers2.length > 0) {
      // Sort by upvotes, take top 10
      papers2.sort((a,b) => (b.paper?.upvotes||0) - (a.paper?.upvotes||0));
      const top = papers2.slice(0, 10);
      return top.map(p => ({
        json: {
          date: yd,
          paper_id: p.paper?.id || '',
          title: p.paper?.title || 'Untitled',
          url: `https://huggingface.co/papers/${p.paper?.id}`,
          upvotes: p.paper?.upvotes || 0
        }
      }));
    }
  }
  throw new Error('No daily papers found for today or yesterday.');
}

// Sort by upvotes, take top 10
papers.sort((a,b) => (b.paper?.upvotes||0) - (a.paper?.upvotes||0));
const top = papers.slice(0, 10);
return top.map(p => ({
  json: {
    date: dateStr,
    paper_id: p.paper?.id || '',
    title: p.paper?.title || 'Untitled',
    url: `https://huggingface.co/papers/${p.paper?.id}`,
    upvotes: p.paper?.upvotes || 0
  }
}));

const lang = 'ko';
const url = $json.url || $item(0).$node['Fetch Daily Papers'].json.url || 'n/a';
const title = $item(0).$node['Fetch Daily Papers'].json.title || '';
const upvotes = $item(0).$node['Fetch Daily Papers'].json.upvotes || 0;
const content = String($json.body || $json.data || $json.content || '').slice(0, 12000);

if (!content || content.length < 100) {
  return [{ json: { ...$item(0).$node['Fetch Daily Papers'].json, ok: false, error_type: 'fetch_failed', error_message: 'Paper content too short or empty' } }];
}

const payload = {
  model: 'solar-pro2',
  temperature: 0.2,
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'paper_summary',
      schema: {
        type: 'object',
        properties: {
          title: { type: 'string' },
          one_line: { type: 'string' },
          problem: { type: 'string' },
          method: { type: 'string' },
          results: { type: 'string' },
          limitations: { type: 'string' },
          tags: { type: 'array', items: { type: 'string' } },
          action_items: { type: 'array', items: { type: 'string' } }
        },
        required: ['title', 'one_line', 'problem', 'method', 'results', 'limitations', 'tags', 'action_items'],
        additionalProperties: false
      }
    }
  },
  messages: [
    { role: 'system', content: '너는 논문 리뷰 어시스턴트다. 입력 텍스트를 읽고 ' + lang + '로만 답해라. 과장 금지. 수치/조건은 최대한 보존하라.' },
    { role: 'user', content: '다음 논문을 분석해 구조화 요약 JSON으로 만들어줘.\n원본 URL: ' + url + '\n\n본문:\n' + content }
  ]
};

return [{ json: { ...$item(0).$node['Fetch Daily Papers'].json, content_length: content.length, upstage_payload: payload } }];

const base = {
  paper_id: $item(0).$node['Fetch Daily Papers'].json.paper_id,
  title: $item(0).$node['Fetch Daily Papers'].json.title,
  url: $item(0).$node['Fetch Daily Papers'].json.url,
  upvotes: $item(0).$node['Fetch Daily Papers'].json.upvotes,
  date: $item(0).$node['Fetch Daily Papers'].json.date
};

if ($json.error) {
  return [{ json: { ...base, ok: false, error_type: 'upstage_error', status: $json.error?.statusCode || null, error_message: $json.error?.message || 'Unknown error' } }];
}

const content = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch (e) { parsed = { raw: content }; }
return [{ json: { ...base, ok: true, summary: parsed } }];

const all = $input.all().map(i => i.json);
const date = all[0]?.date || 'unknown';
const successItems = all.filter(x => x.ok !== false);
const failedItems = all.filter(x => x.ok === false);

// Build HTML email
let html = `<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;max-width:680px;margin:0 auto;padding:24px;">`;
html += `<h1 style="font-size:22px;color:#1a1a1a;">📄 HF Daily Papers Digest — ${date}</h1>`;
html += `<p style="color:#6b7280;font-size:14px;">Upstage Solar가 요약한 오늘의 인기 논문 Top ${successItems.length}편</p>`;
html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;

for (const item of successItems) {
  const s = item.summary || {};
  html += `<div style="margin-bottom:28px;">`;
  html += `<h2 style="font-size:17px;margin:0 0 6px;"><a href="${item.url}" style="color:#6c2bd9;text-decoration:none;">${s.title || item.title}</a></h2>`;
  html += `<p style="color:#6b7280;font-size:12px;margin:0 0 10px;">⬆️ ${item.upvotes} upvotes · ${(s.tags||[]).join(', ')}</p>`;
  html += `<p style="font-size:14px;color:#374151;margin:0 0 8px;"><strong>한 줄:</strong> ${s.one_line || '-'}</p>`;
  html += `<table style="font-size:13px;color:#4b5563;border-collapse:collapse;width:100%;">`;
  html += `<tr><td style="padding:4px 8px 4px 0;vertical-align:top;font-weight:600;white-space:nowrap;">문제</td><td style="padding:4px 0;">${s.problem || '-'}</td></tr>`;
  html += `<tr><td style="padding:4px 8px 4px 0;vertical-align:top;font-weight:600;white-space:nowrap;">방법</td><td style="padding:4px 0;">${s.method || '-'}</td></tr>`;
  html += `<tr><td style="padding:4px 8px 4px 0;vertical-align:top;font-weight:600;white-space:nowrap;">결과</td><td style="padding:4px 0;">${s.results || '-'}</td></tr>`;
  html += `<tr><td style="padding:4px 8px 4px 0;vertical-align:top;font-weight:600;white-space:nowrap;">한계</td><td style="padding:4px 0;">${s.limitations || '-'}</td></tr>`;
  html += `</table>`;
  if (s.action_items && s.action_items.length > 0) {
    html += `<p style="font-size:12px;color:#059669;margin:8px 0 0;">💡 ${s.action_items.join(' · ')}</p>`;
  }
  html += `</div>`;
}

if (failedItems.length > 0) {
  html += `<p style="color:#ef4444;font-size:13px;">⚠️ ${failedItems.length}편 요약 실패</p>`;
}

html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;
html += `<p style="color:#9ca3af;font-size:12px;">Powered by <a href="https://www.upstage.ai" style="color:#6c2bd9;">Upstage Solar</a> · <a href="https://huggingface.co/papers" style="color:#6c2bd9;">HuggingFace Daily Papers</a></p>`;
html += `</div>`;

return [{ json: {
  date,
  subject: `📄 HF Daily Papers Digest — ${date} (${successItems.length}편)`,
  html,
  count: all.length,
  success: successItems.length,
  failed: failedItems.length
} }];
